// 1. Get data from previous node
const input = $input.all()[0].json;
const userData = input.userData;
const menuItem = input.menu_item[0]; 

// 2. Prepare basic item details
const quantity = 1;
const basePrice = parseFloat(menuItem.price || "0");
let totalAddonsPrice = 0;
const selectedAddonsCategories = [];

// --- MANDATORY CUSTOMIZATION LOGIC ---
// If the item is customizable, check for mandatory categories
if (menuItem.is_customize === "1" && menuItem.addons_category_list) {
  menuItem.addons_category_list.forEach(category => {
    // Logic matches CustomizationScreen.kt: Only auto-select if mandatory
    if (category.is_mandatory === "1" && category.addons_list && category.addons_list.length > 0) {
      const firstAddon = category.addons_list[0];

      selectedAddonsCategories.push({
        addons_category: category.addons_category || "",
        addons_category_id: category.addons_category_id || "",
        addons_list: [{
          add_ons_id: firstAddon.add_ons_id || "",
          add_ons_name: firstAddon.add_ons_name || "",
          add_ons_price: firstAddon.add_ons_price || "0.00"
        }]
      });

      // Add to running total of addon prices
      totalAddonsPrice += parseFloat(firstAddon.add_ons_price || "0");
    }
  });
}

// 3. Calculate Totals (Internal project logic: (Base + Addons) * Quantity)
const subTotal = (basePrice * quantity).toFixed(2);
const itemTotal = ((basePrice + totalAddonsPrice) * quantity).toFixed(2);

const cartItem = {
  menu_id: menuItem.menu_id,
  name: menuItem.name || "",
  price: basePrice.toFixed(2),
  menu_content_id: menuItem.menu_content_id || "",
  offer_price: menuItem.offer_price || "",
  menu_detail: menuItem.menu_detail || "",
  image: menuItem.image || "",
  availability: menuItem.availability || "",
  food_type_id: menuItem.food_type_id || "",
  food_type_name: menuItem.food_type_name || "",
  is_customize: parseInt(menuItem.is_customize || "0"),
  is_deal: menuItem.is_deal || "0",
  status: menuItem.status || "1",
  is_combo_item: parseInt(menuItem.is_combo_item || "0"),
  combo_item_details: menuItem.combo_item_details || "",
  is_recipes_menu: menuItem.is_recipes_menu || 0,
  in_stock: menuItem.in_stock || "1",
  quantity: quantity,
  subTotal: subTotal,
  itemTotal: itemTotal,
  comment: null, 
  addons_category_list: selectedAddonsCategories 
};

// 4. Stringify the items object (Required by API)
const itemsJsonString = JSON.stringify({ items: [cartItem] });

// 5. Create the main AddToCartRequest body
const requestBody = {
  app_token: userData.appToken || "",
  cart_id: 0,
  items: itemsJsonString,
  restaurant_id: input.restaurantId || "",
  user_id: userData.userId || "",
  isLoggedIn: parseInt(userData.userId) > 0 ? 1 : 0,
  latitude: userData.latitude || "23.0123054",
  longitude: userData.longitude || "72.5040315",
  language_slug: userData.languageSlug || "en",
  order_delivery: "Delivery",
  platform: "android",
  user_timezone: userData.userTimezone || "Asia/Kolkata",
  tip_percent_val: "0",
  driver_tip: "",
  is_wallet_applied: 0,
  is_creditcard: "yes",
  scheduled_date: "",
  slot_open_time: "",
  slot_close_time: ""
};

// 6. Wrap for n8n output
return { 
  json: { 
    requestBody, 
    "Authorization": userData.authorizationToken || "Basic ZWF0YW5jZV8yMDI1X21ycDpFYXRhbmNlQEAyQDI1"
  },
};

